// Example of how color schemes might be assigned based on card number
function getColorScheme(cardNumber) {
  const schemes = [
    { primary: 'Light Blue', secondary: 'Dark Blue' },
    { primary: 'Dark Green', secondary: 'Lighter Green' },
    { primary: 'Light Purple', secondary: 'Dark Purple' },
    { primary: 'Pink', secondary: 'Rose' },
    { primary: 'Purple', secondary: 'Pink' },
    { primary: 'Light Green', secondary: 'Dark Green' }
  ];

  const index = cardNumber % schemes.length;
  return schemes[index];
}

// Usage:
const cardColorScheme = getColorScheme(7); // Returns the 1st scheme (0: Light Blue)


